import React from 'react';
import { Divider, List, ListItem, ListItemText, Typography } from '@mui/material';
import { Link } from 'react-router-dom';
import fetchModel from '../../modelData/models';

const UserList = () => {
  const [users, setUsers] = useState([]); // State để lưu danh sách user

  useEffect(() => {
    fetchModel("/user/list")
      .then((response) => {
        setUsers(response.data); 
      })
      .catch((err) => console.error("Lỗi lấy danh sách user:", err));
  }, []); 
  return (
    <div>
      <Typography variant="h6">User List</Typography>
      <List component="nav">
        {users.map((user) => (
          <React.Fragment key={user._id}>
            {/* Sử dụng component Link của React Router để không bị load lại trang */}
            <ListItem button component={Link} to={`/users/${user._id}`}>
              <ListItemText primary={`${user.first_name} ${user.last_name}`} />
            </ListItem>
            <Divider />
          </React.Fragment>
        ))}
      </List>
    </div>
  );
};

export default UserList;
